/// Multi-session store: mutable adapter tracking SessionMetrics for all
/// active sessions. Lives at the adapter boundary (effects at edges).
///
/// Port: MultiSessionStore (v1 — category-based)
///   addSession(id) -- register a new session with zeroed metrics
///   removeSession(id) -- remove a tracked session
///   updateSession(id, metrics) -- replace metrics for a session
///   getSessions() -- all tracked session metrics (immutable snapshot)
///   getSession(id) -- metrics for a specific session or undefined
///   appendSessionSample(id, samples) -- append per-category sample values
///   getSessionBuffer(id, categoryId) -- per-session buffer for a category
///   getAggregateBuffer(categoryId) -- aggregate buffer across sessions
///   getAggregateWindowBuffer(categoryId, windowId) -- aggregate buffer for a specific time window
///   getSessionWindowBuffer(sessionId, categoryId, windowId) -- session buffer for a specific time window
///   subscribe(callback) -- register state-change listener
///
/// Port: MultiSessionStoreV2Surface (v2 — phosphor rate samples + pulse log)
/// Additive to v1; see the "V2 (phosphor) additive surface" section below.
/// Milestone 10 of the PM v2 rollout deletes the v1 category pathway; until
/// then both surfaces coexist on the same factory return value.

import type {
  SessionMetrics,
  TimeSeriesBuffer,
  RateSample as CategoryRateSample,
  TimeWindowId,
} from "../domain/types";
import type { MetricCategoryId } from "../domain/categoryConfig";
import { createInitialMetrics } from "../domain/metricsAggregator";
import { createBuffer, appendSample } from "../domain/timeSeriesSampler";
import { METRIC_CATEGORIES } from "../domain/categoryConfig";
import {
  createMultiWindowBuffer,
  appendMultiWindowSample,
  type MultiWindowBuffer,
} from "../domain/multiWindowSampler";
import {
  METRIC_IDS,
  PULSE_RETENTION_MS,
  type MetricId,
  type Pulse,
  type RateSample as PhosphorRateSample,
} from "../domain/phosphor/phosphorMetricConfig";
import { prunePulses } from "../domain/phosphor/pulseTiming";

// ---------------------------------------------------------------------------
// Category sample input -- values for each of the 4 metric categories
// ---------------------------------------------------------------------------

export interface CategorySampleInput {
  readonly tokens: number;
  readonly cost: number;
  readonly agents: number;
  readonly latency: number;
}

// ---------------------------------------------------------------------------
// Port type
// ---------------------------------------------------------------------------

export interface MultiSessionStore {
  readonly addSession: (sessionId: string) => void;
  readonly removeSession: (sessionId: string) => void;
  readonly updateSession: (sessionId: string, metrics: SessionMetrics) => void;
  readonly getSessions: () => ReadonlyArray<SessionMetrics>;
  readonly getSession: (sessionId: string) => SessionMetrics | undefined;
  readonly appendSessionSample: (sessionId: string, samples: CategorySampleInput) => void;
  /** Execute a batch of operations, notifying subscribers only once at the end. */
  readonly batchUpdate: (fn: () => void) => void;
  readonly getSessionBuffer: (sessionId: string, categoryId: MetricCategoryId) => TimeSeriesBuffer | undefined;
  readonly getAggregateBuffer: (categoryId: MetricCategoryId) => TimeSeriesBuffer;
  readonly getAggregateWindowBuffer: (categoryId: MetricCategoryId, windowId: TimeWindowId) => TimeSeriesBuffer;
  readonly getSessionWindowBuffer: (sessionId: string, categoryId: MetricCategoryId, windowId: TimeWindowId) => TimeSeriesBuffer | undefined;
  readonly subscribe: (callback: () => void) => () => void;

  // -------------------------------------------------------------------------
  // V2 (phosphor) additive surface — see ADR-049 / v2-phosphor-architecture.md.
  //
  // These methods coexist with the v1 category pathway above until milestone
  // 10 deletes v1. Phosphor domain modules consume only this subset via the
  // structural `PhosphorStoreSurface` type in `domain/phosphor/scopeProjection`.
  // -------------------------------------------------------------------------

  /** Append a rate sample for (session, metric) at time `t` with value `v`. */
  readonly appendRateSample: (
    sessionId: string,
    metric: MetricId,
    t: number,
    v: number,
  ) => void;
  /** Append a pulse event on the named session's pulse log. */
  readonly appendPulse: (sessionId: string, pulse: Pulse) => void;
  /**
   * Return the session's rate-sample history for the requested metric in
   * insertion order (oldest → newest). Empty array when the session has no
   * samples or does not exist.
   */
  readonly getRateHistory: (
    sessionId: string,
    metric: MetricId,
  ) => ReadonlyArray<PhosphorRateSample>;
  /**
   * Return the session's pulse log in insertion order with retention
   * trim applied: pulses older than `PULSE_RETENTION_MS` relative to
   * the reference clock are absent. When `now` is supplied, it is the
   * reference clock; otherwise `Date.now()` is used so callers always
   * observe the "no pulses older than retention" invariant. Empty
   * array when the session has no pulses or does not exist.
   */
  readonly getPulses: (
    sessionId: string,
    now?: number,
  ) => ReadonlyArray<Pulse>;
  /**
   * Return the ordered list of registered session IDs. Registration order
   * is preserved so per-session color assignment is deterministic.
   */
  readonly getSessionIds: () => ReadonlyArray<string>;
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const DEFAULT_BUFFER_CAPACITY = 60;

const CATEGORY_IDS: ReadonlyArray<MetricCategoryId> = ["tokens", "cost", "agents", "latency"];

// ---------------------------------------------------------------------------
// Pure helpers
// ---------------------------------------------------------------------------

/// Extract the value for a given category from the sample input.
const extractCategoryValue = (
  samples: CategorySampleInput,
  categoryId: MetricCategoryId,
): number => samples[categoryId];

/// Create a RateSample from a category value and timestamp.
///
/// Convention: all category values (tokens, cost, agents, context) are stored
/// in the `tokenRate` field of the RateSample. The `costRate` field is set to 0.
/// This reuses the existing RateSample type as a generic "category sample" --
/// the field name is a misnomer for non-token categories but avoids introducing
/// a separate CategorySample type. Consumers should read `tokenRate` to get the
/// category value regardless of which category the buffer represents.
/// TODO: introduce a dedicated CategorySample type to eliminate semantic mismatch.
const createCategorySample = (value: number, timestamp: number): CategoryRateSample => ({
  timestamp,
  tokenRate: value,
  costRate: 0,
});

/// Determine if a category supports aggregation across sessions.
const isCategoryAggregatable = (categoryId: MetricCategoryId): boolean => {
  const category = METRIC_CATEGORIES.find((c) => c.id === categoryId);
  return category?.aggregateApplicable ?? false;
};

/// Create an empty set of buffers for all 4 categories.
const createCategoryBuffers = (): Map<MetricCategoryId, TimeSeriesBuffer> => {
  const buffers = new Map<MetricCategoryId, TimeSeriesBuffer>();
  for (const id of CATEGORY_IDS) {
    buffers.set(id, createBuffer(DEFAULT_BUFFER_CAPACITY));
  }
  return buffers;
};

/// Create an empty set of multi-window buffers for all 4 categories.
const createCategoryMultiWindowBuffers = (): Map<MetricCategoryId, MultiWindowBuffer> => {
  const buffers = new Map<MetricCategoryId, MultiWindowBuffer>();
  for (const id of CATEGORY_IDS) {
    buffers.set(id, createMultiWindowBuffer());
  }
  return buffers;
};

/// Extract the TimeSeriesBuffer for a specific window from a MultiWindowBuffer.
const extractWindowBuffer = (
  multiWindowBuffer: MultiWindowBuffer,
  windowId: TimeWindowId,
): TimeSeriesBuffer => {
  const windowState = multiWindowBuffer.windows[windowId];
  if (!windowState) {
    return createBuffer(DEFAULT_BUFFER_CAPACITY);
  }
  return windowState.buffer;
};

// ---------------------------------------------------------------------------
// Factory
// ---------------------------------------------------------------------------

/** Create a multi-session store backed by an in-memory Map. */
export const createMultiSessionStore = (): MultiSessionStore => {
  const sessions = new Map<string, SessionMetrics>();
  const sessionBuffers = new Map<string, Map<MetricCategoryId, TimeSeriesBuffer>>();
  const aggregateBuffers = new Map<MetricCategoryId, TimeSeriesBuffer>();
  const sessionMultiWindowBuffers = new Map<string, Map<MetricCategoryId, MultiWindowBuffer>>();
  const aggregateMultiWindowBuffers = new Map<MetricCategoryId, MultiWindowBuffer>();
  const subscribers = new Set<() => void>();

  // Running aggregate sums per category (delta-updated, not recomputed from all sessions)
  const aggregateSums = new Map<MetricCategoryId, number>();
  // Last-known value per session per category (for delta computation)
  const lastSessionValues = new Map<string, Map<MetricCategoryId, number>>();

  // V2 phosphor storage — per-session per-metric rate samples + per-session pulse log.
  // Arrays grow on append; read-time callers are responsible for windowing.
  const sessionRateHistories = new Map<
    string,
    Map<MetricId, PhosphorRateSample[]>
  >();
  const sessionPulseLogs = new Map<string, Pulse[]>();

  // Initialize aggregate buffers and sums for all categories
  for (const id of CATEGORY_IDS) {
    aggregateBuffers.set(id, createBuffer(DEFAULT_BUFFER_CAPACITY));
    aggregateMultiWindowBuffers.set(id, createMultiWindowBuffer());
    aggregateSums.set(id, 0);
  }

  /** Initialize empty v2 rate-history buckets for a newly-added session. */
  const initPhosphorBuckets = (sessionId: string): void => {
    const metricMap = new Map<MetricId, PhosphorRateSample[]>();
    for (const metric of METRIC_IDS) metricMap.set(metric, []);
    sessionRateHistories.set(sessionId, metricMap);
    sessionPulseLogs.set(sessionId, []);
  };

  let batchDepth = 0;
  let batchDirty = false;

  const notifySubscribers = (): void => {
    if (batchDepth > 0) {
      batchDirty = true;
      return;
    }
    for (const callback of subscribers) {
      callback();
    }
  };

  const batchUpdate = (fn: () => void): void => {
    batchDepth++;
    try {
      fn();
    } finally {
      batchDepth--;
      if (batchDepth === 0 && batchDirty) {
        batchDirty = false;
        for (const callback of subscribers) {
          callback();
        }
      }
    }
  };

  const addSession = (sessionId: string): void => {
    if (sessions.has(sessionId)) return;
    sessions.set(sessionId, createInitialMetrics(sessionId));
    sessionBuffers.set(sessionId, createCategoryBuffers());
    sessionMultiWindowBuffers.set(sessionId, createCategoryMultiWindowBuffers());
    const valueMap = new Map<MetricCategoryId, number>();
    for (const id of CATEGORY_IDS) valueMap.set(id, 0);
    lastSessionValues.set(sessionId, valueMap);
    initPhosphorBuckets(sessionId);
    // ADR-049 Contract A: lifecycle mutations notify via the same pub/sub.
    notifySubscribers();
  };

  const removeSession = (sessionId: string): void => {
    // Idempotent: no notification unless the session actually existed.
    if (!sessions.has(sessionId)) return;
    // Subtract this session's last values from running aggregates
    const valueMap = lastSessionValues.get(sessionId);
    if (valueMap) {
      for (const categoryId of CATEGORY_IDS) {
        if (isCategoryAggregatable(categoryId)) {
          const oldValue = valueMap.get(categoryId) ?? 0;
          aggregateSums.set(categoryId, (aggregateSums.get(categoryId) ?? 0) - oldValue);
        }
      }
    }
    sessions.delete(sessionId);
    sessionBuffers.delete(sessionId);
    sessionMultiWindowBuffers.delete(sessionId);
    lastSessionValues.delete(sessionId);
    sessionRateHistories.delete(sessionId);
    sessionPulseLogs.delete(sessionId);
    // ADR-049 Contract A: lifecycle mutations notify via the same pub/sub.
    notifySubscribers();
  };

  const updateSession = (sessionId: string, metrics: SessionMetrics): void => {
    if (sessions.has(sessionId)) {
      sessions.set(sessionId, metrics);
    }
  };

  const getSessions = (): ReadonlyArray<SessionMetrics> =>
    Array.from(sessions.values());

  const getSession = (sessionId: string): SessionMetrics | undefined =>
    sessions.get(sessionId);

  const appendSessionSample = (sessionId: string, samples: CategorySampleInput): void => {
    const categoryBufferMap = sessionBuffers.get(sessionId);
    if (!categoryBufferMap) return;

    const timestamp = Date.now();
    const sessionMwBufferMap = sessionMultiWindowBuffers.get(sessionId);
    const valueMap = lastSessionValues.get(sessionId);

    // Append per-category samples and delta-update aggregates in a single pass
    for (const categoryId of CATEGORY_IDS) {
      const value = extractCategoryValue(samples, categoryId);
      const rateSample = createCategorySample(value, timestamp);

      // Per-session single-window buffer
      const currentBuffer = categoryBufferMap.get(categoryId)!;
      categoryBufferMap.set(categoryId, appendSample(currentBuffer, rateSample));

      // Per-session multi-window buffers
      if (sessionMwBufferMap) {
        const currentMwBuffer = sessionMwBufferMap.get(categoryId)!;
        sessionMwBufferMap.set(categoryId, appendMultiWindowSample(currentMwBuffer, rateSample));
      }

      // Delta-update running aggregate sum (O(1) instead of O(sessions))
      if (isCategoryAggregatable(categoryId)) {
        const oldValue = valueMap?.get(categoryId) ?? 0;
        const newSum = (aggregateSums.get(categoryId) ?? 0) - oldValue + value;
        aggregateSums.set(categoryId, newSum);
        valueMap?.set(categoryId, value);

        // Append aggregate sample to both single-window and multi-window buffers
        const aggregateSample = createCategorySample(newSum, timestamp);

        const currentAggregate = aggregateBuffers.get(categoryId)!;
        aggregateBuffers.set(categoryId, appendSample(currentAggregate, aggregateSample));

        const currentAggMwBuffer = aggregateMultiWindowBuffers.get(categoryId)!;
        aggregateMultiWindowBuffers.set(
          categoryId,
          appendMultiWindowSample(currentAggMwBuffer, aggregateSample),
        );
      }
    }

    notifySubscribers();
  };

  const getSessionBuffer = (
    sessionId: string,
    categoryId: MetricCategoryId,
  ): TimeSeriesBuffer | undefined => {
    const categoryBufferMap = sessionBuffers.get(sessionId);
    if (!categoryBufferMap) return undefined;
    return categoryBufferMap.get(categoryId);
  };

  const getAggregateBuffer = (categoryId: MetricCategoryId): TimeSeriesBuffer =>
    aggregateBuffers.get(categoryId) ?? createBuffer(DEFAULT_BUFFER_CAPACITY);

  const getAggregateWindowBuffer = (
    categoryId: MetricCategoryId,
    windowId: TimeWindowId,
  ): TimeSeriesBuffer => {
    const multiWindowBuffer = aggregateMultiWindowBuffers.get(categoryId);
    if (!multiWindowBuffer) {
      return createBuffer(DEFAULT_BUFFER_CAPACITY);
    }
    return extractWindowBuffer(multiWindowBuffer, windowId);
  };

  const getSessionWindowBuffer = (
    sessionId: string,
    categoryId: MetricCategoryId,
    windowId: TimeWindowId,
  ): TimeSeriesBuffer | undefined => {
    const sessionMwBufferMap = sessionMultiWindowBuffers.get(sessionId);
    if (!sessionMwBufferMap) return undefined;
    const multiWindowBuffer = sessionMwBufferMap.get(categoryId);
    if (!multiWindowBuffer) return undefined;
    return extractWindowBuffer(multiWindowBuffer, windowId);
  };

  const subscribe = (callback: () => void): (() => void) => {
    subscribers.add(callback);
    return () => {
      subscribers.delete(callback);
    };
  };

  // ---------------------------------------------------------------------------
  // V2 phosphor methods (additive)
  // ---------------------------------------------------------------------------

  const appendRateSample = (
    sessionId: string,
    metric: MetricId,
    t: number,
    v: number,
  ): void => {
    const metricMap = sessionRateHistories.get(sessionId);
    if (!metricMap) return; // unknown session -- silently drop (v1 parity)
    const history = metricMap.get(metric);
    if (!history) return;
    history.push({ t, v });
    notifySubscribers();
  };

  const appendPulse = (sessionId: string, pulse: Pulse): void => {
    const log = sessionPulseLogs.get(sessionId);
    if (!log) return;
    log.push(pulse);
    notifySubscribers();
  };

  const getRateHistory = (
    sessionId: string,
    metric: MetricId,
  ): ReadonlyArray<PhosphorRateSample> => {
    const metricMap = sessionRateHistories.get(sessionId);
    if (!metricMap) return [];
    const history = metricMap.get(metric);
    return history ?? [];
  };

  const getPulses = (
    sessionId: string,
    now?: number,
  ): ReadonlyArray<Pulse> => {
    const log = sessionPulseLogs.get(sessionId);
    if (!log) return [];
    // Retention trim is idempotent and always applied. When `now` is
    // supplied (e.g. by scopeProjection), use it so trimming aligns with
    // the frame's logical clock. Otherwise fall back to wall-clock
    // `Date.now()` so callers never observe pulses older than the
    // retention cutoff (the "pulses older than 5s are absent from
    // store.getPulses" invariant).
    const reference = now ?? Date.now();
    return prunePulses(log, reference, PULSE_RETENTION_MS);
  };

  const getSessionIds = (): ReadonlyArray<string> => Array.from(sessions.keys());

  return {
    addSession,
    removeSession,
    updateSession,
    getSessions,
    getSession,
    appendSessionSample,
    batchUpdate,
    getSessionBuffer,
    getAggregateBuffer,
    getAggregateWindowBuffer,
    getSessionWindowBuffer,
    subscribe,
    // v2 phosphor additive surface
    appendRateSample,
    appendPulse,
    getRateHistory,
    getPulses,
    getSessionIds,
  };
};

src/plugins/norbert-usage/domain/phospho.source:
/**
 * Pulse timing — pure helpers for pulse lifetime + store retention.
 *
 * Two responsibilities, each one pure function:
 *
 *   1. `decayFactor(ageMs, lifetimeMs)` — maps a pulse's age to a visual
 *      decay factor in [0, 1]. `1` is fully fresh; `0` is at the lifetime
 *      boundary. The mapping is linear and clamped: negative ages (future
 *      pulse timestamps, which can arise from clock skew) clamp to 1; ages
 *      past the lifetime clamp to 0. This makes the "visible vs invisible"
 *      distinction a direct `decay > 0` check for downstream consumers.
 *
 *   2. `prunePulses(log, now, cutoffMs)` — returns a NEW readonly array of
 *      pulses whose age `(now - p.t)` is ≤ `cutoffMs`. Never mutates the
 *      input log. Used by the store's `getPulses(sessionId, now)` to trim
 *      on read against the retention window.
 *
 * Pure: no imports from `react`, `adapters`, `views`, `window`, or `document`.
 * Depends only on the seam types in `phosphorMetricConfig`.
 */

import type { Pulse } from "./phosphorMetricConfig";

// ---------------------------------------------------------------------------
// decayFactor
// ---------------------------------------------------------------------------

/**
 * Linear decay from 1 (fresh) to 0 (at lifetime boundary), clamped outside
 * `[0, lifetimeMs]`.
 *
 * Examples (lifetime = 2500ms):
 *   - age =   0 → 1.00  (fully fresh)
 *   - age = 1250 → 0.50  (mid-life)
 *   - age = 2500 → 0.00  (boundary)
 *   - age = 3000 → 0.00  (clamped)
 *   - age = -500 → 1.00  (clamped — negative ages treated as fresh)
 */
export const decayFactor = (ageMs: number, lifetimeMs: number): number => {
  if (ageMs <= 0) return 1;
  if (ageMs >= lifetimeMs) return 0;
  return 1 - ageMs / lifetimeMs;
};

// ---------------------------------------------------------------------------
// prunePulses
// ---------------------------------------------------------------------------

/**
 * Return a NEW array containing pulses whose age `(now - p.t)` is ≤
 * `cutoffMs`. The input is never mutated. Idempotent when re-applied with
 * the same `(now, cutoffMs)`.
 *
 * Order is preserved from the input log so callers observing time-ordered
 * inputs continue to observe time-ordered outputs.
 */
export const prunePulses = (
  log: ReadonlyArray<Pulse>,
  now: number,
  cutoffMs: number,
): ReadonlyArray<Pulse> => log.filter((pulse) => now - pulse.t <= cutoffMs);

/**
 * Rate-derivation helpers — count-and-window to RateSample conversions.
 *
 * The phosphor scope ingests upstream activity (hook events, OTel log arrivals,
 * tool-call events) and must project it as per-second rate samples at the
 * RATE_TICK_MS cadence. Each helper in this module is a pure function of a
 * count, a window length, and a tick-boundary timestamp. They do not mutate
 * any store — the caller appends the returned sample.
 *
 * Semantics (v2-phosphor-architecture §5 Q1):
 *   deriveEventsRate(count, windowMs, tickBoundaryT)
 *     = { t: tickBoundaryT, v: count / (windowMs / 1000) }
 *   deriveToolCallsRate(toolCallCount, windowMs, tickBoundaryT)
 *     = { t: tickBoundaryT, v: toolCallCount / (windowMs / 1000) }
 *
 * Steps 08-01 / 08-02 / 08-03 deliver the derivation surface in sequence:
 * `deriveEventsRate`, `deriveTokensRate`, and `deriveToolCallsRate` share
 * this module so the full set stays discoverable in a single pure file
 * under `domain/phosphor/`.
 *
 * Pure: no effects, no imports outside `phosphorMetricConfig` (seam types).
 * Composes trivially at the hookProcessor effect boundary.
 */

import type { RateSample } from "./phosphorMetricConfig";

// ---------------------------------------------------------------------------
// Internal helpers — small, well-named, reusable across rate helpers
// ---------------------------------------------------------------------------

/** Convert a window length in milliseconds to its equivalent in seconds. */
const windowSeconds = (windowMs: number): number => windowMs / 1000;

/** Compute a per-second rate from a count across a window. */
const perSecond = (count: number, windowMs: number): number =>
  count / windowSeconds(windowMs);

// ---------------------------------------------------------------------------
// Public API — one function per rate helper
// ---------------------------------------------------------------------------

/**
 * Derive an events-per-second `RateSample` from a windowed event count.
 *
 * `count` is the number of hook events (and OTel log arrivals, when the
 * upstream stream blends them) observed across the preceding `windowMs`
 * interval. `tickBoundaryT` is the tick-boundary timestamp assigned to the
 * returned sample; the store appends it as-is.
 *
 * Pure: total over finite non-negative inputs. No validation — callers upstream
 * are responsible for passing `windowMs > 0` and `count >= 0`. The function is
 * intentionally permissive so it composes cleanly inside pipelines.
 */
export const deriveEventsRate = (
  count: number,
  windowMs: number,
  tickBoundaryT: number,
): RateSample => ({
  t: tickBoundaryT,
  v: perSecond(count, windowMs),
});

/**
 * Derive a tokens-per-second `RateSample` from an OTel api-request event.
 *
 * `totalTokens` is the total token count reported by the api-request event
 * (input + output + cache tokens as aggregated upstream). `durationMs` is the
 * wall-clock duration the request took. `tickBoundaryT` is the timestamp the
 * store will append on the returned sample.
 *
 * Semantics (v2-phosphor-architecture §5 Q1):
 *   deriveTokensRate(totalTokens, durationMs, t)
 *     = { t, v: totalTokens / (durationMs / 1000) }
 *
 * Zero-duration defensive lock: a `durationMs <= 0` yields `v = 0` rather
 * than producing `Infinity` or `NaN`. OTel api-request events occasionally
 * arrive with a zero or negative duration (clock skew, partial records); the
 * scope pipeline should emit a silent zero sample rather than crash. Pure:
 * total over all finite inputs.
 */
export const deriveTokensRate = (
  totalTokens: number,
  durationMs: number,
  tickBoundaryT: number,
): RateSample => ({
  t: tickBoundaryT,
  v: durationMs > 0 ? perSecond(totalTokens, durationMs) : 0,
});

/**
 * Derive a tool-calls-per-second `RateSample` from a windowed tool-call count.
 *
 * `toolCallCount` is the number of tool-call events observed for a session
 * across the preceding `windowMs` interval. `tickBoundaryT` is the
 * tick-boundary timestamp assigned to the returned sample; the store
 * appends it as-is.
 *
 * Semantics (v2-phosphor-architecture §5 Q1):
 *   deriveToolCallsRate(toolCallCount, windowMs, t)
 *     = { t, v: toolCallCount / (windowMs / 1000) }
 *
 * Pure: total over finite non-negative inputs. Shape mirrors
 * `deriveEventsRate` — both are windowed counters. Kept as a distinct named
 * function so the derivation seam names match the `MetricId` domain
 * vocabulary (`events` vs `toolcalls`) at the hookProcessor boundary.
 */
export const deriveToolCallsRate = (
  toolCallCount: number,
  windowMs: number,
  tickBoundaryT: number,
): RateSample => ({
  t: tickBoundaryT,
  v: perSecond(toolCallCount, windowMs),
});

/**
 * Scope hit-test — pure snap-to-nearest-trace over a projected Frame.
 *
 * Given a pointer position in canvas coordinates and a Frame, return the
 * HoverSelection identifying the nearest trace within HOVER_SNAP_DISTANCE_PX
 * vertically at the pointer's x-time, or `null` when no trace is close enough.
 *
 * Geometry contract (matches the canvas coordinate system used by the scope):
 *   - timeToX(t, width, now) = width * (1 - (now - t) / WINDOW_MS)
 *     (older-left, newer-right; the newest sample sits at x = width)
 *   - valueToY(v, height, yMax) = height * (1 - v / yMax)
 *     (low-value-bottom, high-value-top; canvas origin is top-left)
 *
 * Algorithm:
 *   1. Reject pointers outside [0, width] x [0, height].
 *   2. Convert pointer.x to a cursor-time via the inverse of timeToX.
 *   3. For each trace, find the sample whose time is nearest the cursor-time
 *      (this is the column the pointer is over).
 *   4. Compute the trace's displayY at that sample. An off-canvas sample
 *      (value above yMax, or negative) is visually clipped to the nearest
 *      canvas edge — its effective distance to a pointer inside the canvas
 *      is measured to the clipped edge, so off-scale traces remain hoverable
 *      anywhere at that x-time (a design choice mirroring the scope's visual
 *      clipping behavior).
 *   5. Pick the trace whose vertical distance is minimum; return null if that
 *      distance exceeds HOVER_SNAP_DISTANCE_PX.
 *
 * Pure: no imports from `react`, `adapters`, `views`, `window`, `document`,
 * or `domain/oscilloscope`. Inspects only the Frame structure and the
 * HOVER_SNAP_DISTANCE_PX constant.
 */

import { WINDOW_MS } from "./phosphorMetricConfig";
import type { Frame, FrameTrace } from "./scopeProjection";

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/**
 * Maximum pixel distance for snap-to-trace hover. Sourced from the prototype
 * spec (28px ≈ thumb-width on a high-DPI laptop display, comfortable for
 * pointer targeting without feeling sticky).
 */
export const HOVER_SNAP_DISTANCE_PX = 28;

// ---------------------------------------------------------------------------
// Public types
// ---------------------------------------------------------------------------

export interface PointerPosition {
  readonly x: number;
  readonly y: number;
  readonly width: number;
  readonly height: number;
}

export interface HoverSelection {
  readonly sessionId: string;
  readonly color: string;
  readonly value: number;
  readonly time: number;
  readonly ageMs: number;
  readonly displayX: number;
  readonly displayY: number;
}

// ---------------------------------------------------------------------------
// Pure geometry helpers — mirror the canvas host's projection math
// ---------------------------------------------------------------------------

/** Map a sample time `t` to x pixels within `[0, width]` given `now`. */
const timeToX = (t: number, width: number, now: number): number =>
  width * (1 - (now - t) / WINDOW_MS);

/** Inverse of timeToX: map a pointer x to a cursor-time given `now`. */
const xToTime = (x: number, width: number, now: number): number =>
  now - (1 - x / width) * WINDOW_MS;

/** Map a sample value `v` to y pixels within `[0, height]` given `yMax`. */
const valueToY = (v: number, height: number, yMax: number): number =>
  height * (1 - v / yMax);

/**
 * Whether a sample's displayY falls outside the visible canvas (above the
 * top, i.e. displayY < 0, or below the bottom, i.e. displayY > height).
 * Off-canvas samples are visually clipped; the scope still renders them at
 * the edge, so the user can hover anywhere in the canvas at that x-time
 * and expect to select this trace.
 */
const isSampleOffCanvas = (sampleY: number, height: number): boolean =>
  sampleY < 0 || sampleY > height;

/**
 * Effective vertical distance from the pointer to a trace sample's visible
 * rendering. On-canvas samples: absolute y-difference. Off-canvas samples:
 * zero — the trace is clipped to the viewport so the user selecting anywhere
 * at that x-time is still over the trace (off-scale signals remain hoverable,
 * a design choice mirroring the scope's visual clipping behavior — an
 * off-scale trace is rendered pinned to the edge and the user should always
 * be able to investigate it).
 */
const verticalDistanceToTrace = (
  sampleY: number,
  pointerY: number,
  height: number,
): number =>
  isSampleOffCanvas(sampleY, height) ? 0 : Math.abs(sampleY - pointerY);

/** Whether the pointer lies inside the canvas rectangle. */
const isPointerInsideCanvas = (pointer: PointerPosition): boolean =>
  pointer.x >= 0 &&
  pointer.x <= pointer.width &&
  pointer.y >= 0 &&
  pointer.y <= pointer.height;

// ---------------------------------------------------------------------------
// Sample-at-cursor — honest-signal lookup for the trace value at the
// cursor-time. Returns the value of the latest sample whose time is at-or-
// before `cursorTime`, mirroring scopeProjection's `sampleAt` semantics so
// hit-test and trace projection stay consistent (see IC-S15).
// ---------------------------------------------------------------------------

/** Value of the latest sample at-or-before `cursorTime`, or `null` when no such sample exists. */
const valueAtCursorTime = (
  trace: FrameTrace,
  cursorTime: number,
): number | null => {
  if (trace.samples.length === 0) return null;
  let latestValue: number | null = null;
  let latestTime = Number.NEGATIVE_INFINITY;
  for (const sample of trace.samples) {
    if (sample.t <= cursorTime && sample.t >= latestTime) {
      latestTime = sample.t;
      latestValue = sample.v;
    }
  }
  // Fallback: if every sample is strictly after cursorTime, snap to the
  // earliest sample (the pointer is to the left of the first observation).
  if (latestValue === null) {
    let earliest = trace.samples[0];
    for (const sample of trace.samples) {
      if (sample.t < earliest.t) earliest = sample;
    }
    latestValue = earliest.v;
  }
  return latestValue;
};

// ---------------------------------------------------------------------------
// Candidate selection — internal record used during the scan
// ---------------------------------------------------------------------------

interface Candidate {
  readonly trace: FrameTrace;
  readonly cursorTime: number;
  readonly cursorValue: number;
  readonly displayX: number;
  readonly displayY: number;
  readonly verticalDistance: number;
}

/**
 * Build a hit-test candidate for a single trace at the cursor-time, or
 * `null` when the trace has no samples.
 *
 * The reported `cursorValue` is the trace's value at the cursor-time
 * (honest-signal lookup — last sample at-or-before cursorTime); the
 * reported `displayX` is the pointer's x (the sample is "at" the pointer's
 * column, not the sample's own column), because the value lookup behaves
 * like a step function across the cursor's timeline.
 */
const candidateForTrace = (
  trace: FrameTrace,
  pointer: PointerPosition,
  frame: Frame,
  cursorTime: number,
): Candidate | null => {
  const cursorValue = valueAtCursorTime(trace, cursorTime);
  if (cursorValue === null) return null;
  const displayX = timeToX(cursorTime, pointer.width, frame.now);
  const displayY = valueToY(cursorValue, pointer.height, frame.yMax);
  const verticalDistance = verticalDistanceToTrace(
    displayY,
    pointer.y,
    pointer.height,
  );
  return {
    trace,
    cursorTime,
    cursorValue,
    displayX,
    displayY,
    verticalDistance,
  };
};

/** Convert the winning candidate into a HoverSelection. */
const toHoverSelection = (
  candidate: Candidate,
  now: number,
): HoverSelection => ({
  sessionId: candidate.trace.sessionId,
  color: candidate.trace.color,
  value: candidate.cursorValue,
  time: candidate.cursorTime,
  ageMs: Math.max(0, now - candidate.cursorTime),
  displayX: candidate.displayX,
  displayY: candidate.displayY,
});

// ---------------------------------------------------------------------------
// scopeHitTest — the driving port
// ---------------------------------------------------------------------------

/**
 * Pure hit-test. Deterministic in (pointer, frame).
 *
 * Returns the HoverSelection for the trace whose sample nearest the pointer's
 * cursor-time has the minimum vertical distance to the pointer, provided
 * that distance is ≤ HOVER_SNAP_DISTANCE_PX. Off-canvas samples (values
 * above yMax or negative) are considered clipped to the canvas edge — a
 * pointer inside the canvas at that x-time is effectively on the clipped
 * trace, so off-scale signals remain hoverable.
 *
 * Returns `null` when:
 *   - the pointer is outside `[0, width] x [0, height]`
 *   - the frame has no traces
 *   - no trace has any samples
 *   - the nearest on-canvas trace is beyond the snap radius
 */
export const scopeHitTest = (
  pointer: PointerPosition,
  frame: Frame,
): HoverSelection | null => {
  if (!isPointerInsideCanvas(pointer)) return null;
  const cursorTime = xToTime(pointer.x, pointer.width, frame.now);
  let winner: Candidate | null = null;
  for (const trace of frame.traces) {
    const candidate = candidateForTrace(trace, pointer, frame, cursorTime);
    if (candidate === null) continue;
    if (winner === null || candidate.verticalDistance < winner.verticalDistance) {
      winner = candidate;
    }
  }
  if (winner === null) return null;
  if (winner.verticalDistance > HOVER_SNAP_DISTANCE_PX) return null;
  return toHoverSelection(winner, frame.now);
};

/**
 * Scope projection — pure transformation from (store, metric, now) to Frame.
 *
 * This is the driving-port pure core for the phosphor scope. A frame is
 * the snapshot the effect-side `PhosphorCanvasHost` renders on each rAF
 * tick. The projection is honest:
 *
 *   - Each active session becomes one trace whose samples are the session's
 *     arrived rate history for the requested metric, trimmed to the 60-second
 *     window ending at `now`. No sub-interval interpolation. No zero-fill.
 *   - Each session's color is deterministic: its registration-order index
 *     modulo `SESSION_COLORS.length`.
 *   - `latestValue` is the most recent arrived sample value (raw, not
 *     EWMA-smoothed) so the legend and trace edge stay honest with the data.
 *   - `pulses` is projected from the store's per-session pulse log (empty
 *     for WS-1 scenarios; populated once WS-2 lands).
 *   - `yMax` and `unit` come from the METRICS config for the requested metric.
 *
 * Pure: no imports from `react`, `adapters`, `views`, `window`, `document`,
 * or `domain/oscilloscope`. The store is consumed via a structural surface
 * (`PhosphorStoreSurface`) so the dependency-cruiser boundary rule for
 * `domain/phosphor/` is not crossed.
 */

import {
  colorForSessionIndex,
  METRICS,
  PULSE_LIFETIME_MS,
  WINDOW_MS,
  type MetricId,
  type Pulse,
  type RateSample,
} from "./phosphorMetricConfig";
import { decayFactor } from "./pulseTiming";

// ---------------------------------------------------------------------------
// Store surface — structural type, satisfied by adapters/multiSessionStore
// ---------------------------------------------------------------------------

/**
 * The minimum store surface required by `buildFrame`. Declared here so the
 * phosphor domain does not reach into `adapters/` (which would violate the
 * functional-paradigm boundary). Any implementation whose method
 * signatures match this interface is a valid projection source.
 */
export interface PhosphorStoreSurface {
  readonly getSessionIds: () => ReadonlyArray<string>;
  readonly getRateHistory: (
    sessionId: string,
    metric: MetricId,
  ) => ReadonlyArray<RateSample>;
  /**
   * Retrieve a session's pulse log. When `now` is supplied, the store
   * prunes pulses older than its retention window; without `now`, the
   * raw log is returned. `buildFrame` always passes `now`.
   */
  readonly getPulses: (
    sessionId: string,
    now?: number,
  ) => ReadonlyArray<Pulse>;
}

// ---------------------------------------------------------------------------
// Frame output shapes — what the effect-side canvas host consumes
// ---------------------------------------------------------------------------

export interface FrameTrace {
  readonly sessionId: string;
  readonly color: string;
  readonly samples: ReadonlyArray<RateSample>;
  readonly latestValue: number | null;
}

export interface FramePulse {
  readonly sessionId: string;
  readonly t: number;
  readonly v: number;
  readonly decay: number;
  readonly strength: number;
  readonly kind: Pulse["kind"];
  readonly color: string;
}

export interface LegendEntry {
  readonly sessionId: string;
  readonly color: string;
  readonly latestValue: number | null;
}

export interface Frame {
  readonly now: number;
  readonly metric: MetricId;
  readonly yMax: number;
  readonly unit: string;
  readonly traces: ReadonlyArray<FrameTrace>;
  readonly pulses: ReadonlyArray<FramePulse>;
  readonly legend: ReadonlyArray<LegendEntry>;
}

// ---------------------------------------------------------------------------
// Pure helpers
// ---------------------------------------------------------------------------

/**
 * Keep only samples whose timestamp is inside the 60-second window ending
 * at `now`. Window-trimming is idempotent — calling repeatedly with the
 * same (history, now) produces the same result.
 */
const trimToWindow = (
  samples: ReadonlyArray<RateSample>,
  now: number,
): ReadonlyArray<RateSample> => {
  const cutoff = now - WINDOW_MS;
  // Filter (not slice) so callers may pass histories that are not strictly
  // sorted by time without risking incorrect truncation.
  return samples.filter((s) => s.t >= cutoff);
};

/** Latest sample's `v`, or `null` when the history is empty. */
const latestValueOf = (samples: ReadonlyArray<RateSample>): number | null =>
  samples.length === 0 ? null : samples[samples.length - 1].v;

/**
 * Honest-signal sample lookup for a pulse's vertical position: find the
 * value at (or most recently before) time `t` in the session's rate
 * history. Returns `0` when no sample at-or-before `t` exists (baseline
 * position — see M2-S8: a session with no arrived history still projects
 * pulses at baseline, without fabricating rate samples).
 *
 * No interpolation between samples. The vertical position is literally
 * the last observed arrival value, which is what "honest signal" means
 * in the phosphor scope design (see v2-phosphor-architecture.md §5 Q1).
 */
const sampleAt = (samples: ReadonlyArray<RateSample>, t: number): number => {
  let latestValue = 0;
  let latestTime = Number.NEGATIVE_INFINITY;
  for (const sample of samples) {
    if (sample.t <= t && sample.t >= latestTime) {
      latestTime = sample.t;
      latestValue = sample.v;
    }
  }
  return latestValue;
};

/** Project a single session's trace for the requested metric. */
const projectTrace = (
  sessionId: string,
  index: number,
  store: PhosphorStoreSurface,
  metric: MetricId,
  now: number,
): FrameTrace => {
  const color = colorForSessionIndex(index);
  const history = store.getRateHistory(sessionId, metric);
  const samples = trimToWindow(history, now);
  return {
    sessionId,
    color,
    samples,
    latestValue: latestValueOf(samples),
  };
};

/** Derive the legend row for a trace — same identity triple. */
const legendEntryFor = (trace: FrameTrace): LegendEntry => ({
  sessionId: trace.sessionId,
  color: trace.color,
  latestValue: trace.latestValue,
});

/**
 * Project a single pulse into a `FramePulse`. The vertical position (`v`)
 * is looked up from the session's trace samples at the pulse's time —
 * this enforces the honest-signal invariant: a pulse sits on the trace
 * line, not between interpolated points.
 */
const projectPulse = (
  pulse: Pulse,
  trace: FrameTrace,
  now: number,
): FramePulse => ({
  sessionId: trace.sessionId,
  t: pulse.t,
  v: sampleAt(trace.samples, pulse.t),
  decay: decayFactor(now - pulse.t, PULSE_LIFETIME_MS),
  strength: pulse.strength,
  kind: pulse.kind,
  color: trace.color,
});

/**
 * Project all visible pulses for a single session's trace. "Visible"
 * means `decay > 0` — pulses at or past the lifetime boundary are absent
 * from the frame even if the store still retains them (retention window
 * > visual lifetime by design).
 */
const projectPulsesForTrace = (
  trace: FrameTrace,
  store: PhosphorStoreSurface,
  now: number,
): ReadonlyArray<FramePulse> => {
  const pulses = store.getPulses(trace.sessionId, now);
  const projected: FramePulse[] = [];
  for (const pulse of pulses) {
    const framePulse = projectPulse(pulse, trace, now);
    if (framePulse.decay > 0) projected.push(framePulse);
  }
  return projected;
};

/**
 * Stable sort by strength descending. Pulses with higher strength appear
 * first; equal-strength pulses preserve their input relative order (stable).
 *
 * Renderer contract: the dominant flare (tool, strength 1.0) paints on top
 * of softer pulses (subagent 0.75, lifecycle 0.5), so the frame must expose
 * pulses in strength-descending order regardless of store insertion order.
 *
 * Returns a NEW array; the input is never mutated.
 */
const sortPulsesByStrengthDescending = (
  pulses: ReadonlyArray<FramePulse>,
): ReadonlyArray<FramePulse> => {
  // Decorate-sort-undecorate to guarantee stability under engines whose
  // Array#sort is stable (Node/V8 since 10.x). The index tiebreak keeps
  // equal-strength pulses in their original relative order.
  const decorated = pulses.map((pulse, index) => ({ pulse, index }));
  decorated.sort((a, b) => {
    if (b.pulse.strength !== a.pulse.strength) {
      return b.pulse.strength - a.pulse.strength;
    }
    return a.index - b.index;
  });
  return decorated.map((entry) => entry.pulse);
};

// ---------------------------------------------------------------------------
// buildFrame — the driving port
// ---------------------------------------------------------------------------

/**
 * Pure projection. Deterministic in (store snapshot, metric, now). No side
 * effects, no hidden state.
 *
 * Contract:
 *   - One trace per session returned by `store.getSessionIds()`.
 *   - Trace samples are the session's arrived rate history, trimmed to
 *     the 60s window ending at `now`.
 *   - Trace color is assigned by session-registration index into
 *     `SESSION_COLORS` (palette-wrapping beyond its length).
 *   - `latestValue` is the most recent raw arrived value, or `null`.
 *   - `yMax` and `unit` come from `METRICS[metric]`.
 *   - `pulses` contains one `FramePulse` per still-visible pulse across
 *     all sessions. A pulse is visible iff `decay(age, PULSE_LIFETIME_MS)`
 *     is greater than 0; pulses at or past the lifetime are absent even
 *     if the store retains them (retention > lifetime by design). Pulses
 *     are sorted by strength descending (stable within equal strength),
 *     so the dominant flare renders on top of softer ones.
 *   - `legend` parallels `traces` 1:1.
 */
export const buildFrame = (
  store: PhosphorStoreSurface,
  metric: MetricId,
  now: number,
): Frame => {
  const sessionIds = store.getSessionIds();
  const traces = sessionIds.map((sessionId, index) =>
    projectTrace(sessionId, index, store, metric, now),
  );
  const pulses = sortPulsesByStrengthDescending(
    traces.flatMap((trace) => projectPulsesForTrace(trace, store, now)),
  );
  const legend = traces.map(legendEntryFor);
  const config = METRICS[metric];
  return {
    now,
    metric,
    yMax: config.yMax,
    unit: config.unit,
    traces,
    pulses,
    legend,
  };
};

