/**
 * Unit tests: Multi-Session Store adapter (Step 01-01)
 *
 * Tracks SessionMetrics for all active sessions. Mutable adapter at the edge.
 *
 * Behaviors tested:
 * - Initial state has no sessions
 * - addSession registers a new session with initial metrics
 * - removeSession removes a tracked session
 * - updateSession replaces metrics for a tracked session
 * - getSessions returns all tracked session metrics
 * - getSession returns metrics for a specific session or undefined
 * - Adding duplicate session ID is idempotent (keeps existing)
 * - Removing non-existent session is a no-op
 */

import { describe, it, expect, vi, afterEach } from "vitest";
import { createMultiSessionStore } from "../../../../../src/plugins/norbert-usage/adapters/multiSessionStore";
import { createInitialMetrics } from "../../../../../src/plugins/norbert-usage/domain/metricsAggregator";
import type { SessionMetrics } from "../../../../../src/plugins/norbert-usage/domain/types";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const makeMetrics = (
  sessionId: string,
  overrides: Partial<SessionMetrics> = {},
): SessionMetrics => ({
  ...createInitialMetrics(sessionId),
  ...overrides,
});

// ---------------------------------------------------------------------------
// Initial state
// ---------------------------------------------------------------------------

describe("multiSessionStore initial state", () => {
  it("has no sessions initially", () => {
    const store = createMultiSessionStore();
    expect(store.getSessions()).toHaveLength(0);
  });
});

// ---------------------------------------------------------------------------
// Add/remove sessions
// ---------------------------------------------------------------------------

describe("multiSessionStore add and remove", () => {
  it("addSession registers a new session", () => {
    const store = createMultiSessionStore();
    store.addSession("session-a");

    const sessions = store.getSessions();
    expect(sessions).toHaveLength(1);
    expect(sessions[0].sessionId).toBe("session-a");
  });

  it("addSession with duplicate ID is idempotent", () => {
    const store = createMultiSessionStore();
    store.addSession("session-a");
    store.addSession("session-a");

    expect(store.getSessions()).toHaveLength(1);
  });

  it("removeSession removes tracked session", () => {
    const store = createMultiSessionStore();
    store.addSession("session-a");
    store.addSession("session-b");
    store.removeSession("session-a");

    const sessions = store.getSessions();
    expect(sessions).toHaveLength(1);
    expect(sessions[0].sessionId).toBe("session-b");
  });

  it("removeSession on non-existent session is a no-op", () => {
    const store = createMultiSessionStore();
    store.addSession("session-a");
    store.removeSession("non-existent");

    expect(store.getSessions()).toHaveLength(1);
  });
});

// ---------------------------------------------------------------------------
// Update and query
// ---------------------------------------------------------------------------

describe("multiSessionStore update and query", () => {
  it("updateSession replaces metrics for tracked session", () => {
    const store = createMultiSessionStore();
    store.addSession("session-a");

    const updated = makeMetrics("session-a", { burnRate: 250, sessionCost: 3.5 });
    store.updateSession("session-a", updated);

    const result = store.getSession("session-a");
    expect(result).toBeDefined();
    expect(result!.burnRate).toBe(250);
    expect(result!.sessionCost).toBe(3.5);
  });

  it("getSession returns undefined for unknown session", () => {
    const store = createMultiSessionStore();
    expect(store.getSession("unknown")).toBeUndefined();
  });

  it("tracks add and remove of sessions independently", () => {
    const store = createMultiSessionStore();
    store.addSession("alpha");
    store.addSession("beta");
    store.addSession("gamma");

    store.updateSession("beta", makeMetrics("beta", { burnRate: 100 }));
    store.removeSession("alpha");

    const sessions = store.getSessions();
    expect(sessions).toHaveLength(2);
    expect(sessions.map(s => s.sessionId).sort()).toEqual(["beta", "gamma"]);

    const beta = store.getSession("beta");
    expect(beta!.burnRate).toBe(100);
  });

  it("updateSession on unknown ID is a no-op", () => {
    const store = createMultiSessionStore();
    store.addSession("session-a");

    const before = store.getSession("session-a");
    store.updateSession("unknown-id", makeMetrics("unknown-id", { burnRate: 999 }));

    // Original session unchanged
    const after = store.getSession("session-a");
    expect(after).toEqual(before);

    // Unknown session was not created
    expect(store.getSession("unknown-id")).toBeUndefined();
    expect(store.getSessions()).toHaveLength(1);
  });
});

// ---------------------------------------------------------------------------
// Aggregate window buffer -- cross-session sum
// ---------------------------------------------------------------------------

describe("multiSessionStore aggregate window buffer", () => {
  afterEach(() => {
    vi.restoreAllMocks();
  });

  it("sums values across two sessions in the 1m window buffer", () => {
    // Control timestamps to ensure the aggregate multi-window buffer accepts both samples.
    // The 1m window has a 2000ms sample interval (aligned with the 2s heartbeat
    // poll), so timestamps must be >2000ms apart for the second append to pass
    // the downsample gate in multiWindowSampler.appendToWindow.
    let now = 1000;
    vi.spyOn(Date, "now").mockImplementation(() => now);

    const store = createMultiSessionStore();
    store.addSession("session-a");
    store.addSession("session-b");

    // First sample at t=1000
    store.appendSessionSample("session-a", { tokens: 100, cost: 0, agents: 0, context: 0 });

    // Advance time past the 1m window's 2000ms sample interval
    now = 3100;
    store.appendSessionSample("session-b", { tokens: 250, cost: 0, agents: 0, context: 0 });

    // tokens is aggregateApplicable, so the aggregate window should sum both
    const aggregateBuffer = store.getAggregateWindowBuffer("tokens", "1m");
    expect(aggregateBuffer.samples.length).toBeGreaterThan(0);

    // The latest aggregate sample should reflect the sum of both sessions
    const latestSample = aggregateBuffer.samples[aggregateBuffer.samples.length - 1];
    expect(latestSample.tokenRate).toBe(350);
  });

  it("does not aggregate non-aggregatable categories (context)", () => {
    let now = 1000;
    vi.spyOn(Date, "now").mockImplementation(() => now);

    const store = createMultiSessionStore();
    store.addSession("session-a");
    store.addSession("session-b");

    store.appendSessionSample("session-a", { tokens: 0, cost: 0, agents: 0, context: 60 });
    now = 1200;
    store.appendSessionSample("session-b", { tokens: 0, cost: 0, agents: 0, context: 80 });

    // context is not aggregateApplicable -- aggregate window buffer should be empty
    const aggregateBuffer = store.getAggregateWindowBuffer("context", "1m");
    expect(aggregateBuffer.samples).toHaveLength(0);
  });
});

// ---------------------------------------------------------------------------
// Null-fallback paths in buffer retrieval
// ---------------------------------------------------------------------------

describe("multiSessionStore buffer fallback paths", () => {
  it("getSessionWindowBuffer returns undefined for unknown session", () => {
    const store = createMultiSessionStore();
    const result = store.getSessionWindowBuffer("unknown-session", "tokens", "1m");
    expect(result).toBeUndefined();
  });

  it("getSessionWindowBuffer returns empty buffer for session with no samples", () => {
    const store = createMultiSessionStore();
    store.addSession("session-a");

    // Session exists but no samples appended yet -- multi-window buffer exists with empty windows
    const result = store.getSessionWindowBuffer("session-a", "tokens", "1m");
    expect(result).toBeDefined();
    expect(result!.samples).toHaveLength(0);
  });

  it("getAggregateWindowBuffer returns empty buffer for category with no samples", () => {
    const store = createMultiSessionStore();

    // No sessions added, no samples -- aggregate multi-window buffer should return empty
    const result = store.getAggregateWindowBuffer("tokens", "1m");
    expect(result).toBeDefined();
    expect(result.samples).toHaveLength(0);
  });

  it("getSessionBuffer returns undefined for unknown session", () => {
    const store = createMultiSessionStore();
    const result = store.getSessionBuffer("unknown-session", "tokens");
    expect(result).toBeUndefined();
  });

  it("appendSessionSample on unknown session is a no-op", () => {
    const store = createMultiSessionStore();
    store.addSession("session-a");

    // Append to unknown session -- should not throw, should not affect existing
    store.appendSessionSample("unknown-session", { tokens: 100, cost: 0, agents: 0, context: 0 });

    const buffer = store.getSessionBuffer("session-a", "tokens");
    expect(buffer).toBeDefined();
    expect(buffer!.samples).toHaveLength(0);
  });
});

tests/unit/plugins/norbert-usage/event-p.source:
/**
 * Integration test: Event Pipeline (DB event → hookProcessor → metricsStore)
 *
 * This test exercises the full frontend event pipeline using production-shaped
 * event payloads (as returned by Tauri IPC `get_session_events`).
 *
 * The bug this catches: hookProcessor received the full DB event wrapper
 * { session_id, event_type, payload: { usage: {...} }, ... } but passed it
 * as-is to the aggregator. The token extractor looked for `payload.usage`
 * at the wrong nesting level and always returned "absent".
 *
 * This test wires up the real plugin onLoad, feeds production-shaped events
 * through the registered hook processor, and asserts the metrics store
 * reflects extracted tokens and computed costs.
 *
 * NOTE: usageMetricsStore is a module-level singleton that accumulates state
 * across tests. Tests use delta assertions (before/after) instead of absolute
 * values.
 */

import { describe, it, expect, beforeAll } from "vitest";
import { usageMetricsStore } from "../../../../src/plugins/norbert-usage/index";
import { norbertUsagePlugin } from "../../../../src/plugins/norbert-usage/index";
import { resetHookBridge, deliverHookEvent } from "../../../../src/plugins/hookBridge";
import { createPluginRegistry } from "../../../../src/plugins/pluginRegistry";
import { createNorbertAPI } from "../../../../src/plugins/apiFactory";
import { loadPlugins } from "../../../../src/plugins/lifecycleManager";
import { norbertSessionPlugin } from "../../../../src/plugins/norbert-session/index";

// ---------------------------------------------------------------------------
// Production event shapes — exactly what get_session_events returns via IPC
// ---------------------------------------------------------------------------

/** An OTel api_request event WITH token usage -- the sole cost-bearing
 *  event type under the OTel-authoritative policy. */
const makeWrappedApiRequestWithUsage = (sessionId: string) => ({
  session_id: sessionId,
  event_type: "api_request",
  payload: {
    session_id: sessionId,
    usage: {
      input_tokens: 1200,
      output_tokens: 400,
      cache_read_input_tokens: 500,
      cache_creation_input_tokens: 0,
      model: "claude-sonnet-4-20250514",
    },
  },
  received_at: "2026-03-13T22:00:00Z",
  provider: "otel",
});

/** A hook tool_call_end with usage -- refreshes context window but must
 *  NOT credit tokens/cost. */
const makeWrappedHookToolCallEndWithUsage = (sessionId: string) => ({
  session_id: sessionId,
  event_type: "tool_call_end",
  payload: {
    session_id: sessionId,
    tool: "Read",
    input: { file_path: "/tmp/test.ts" },
    usage: {
      input_tokens: 1200,
      output_tokens: 400,
      cache_read_input_tokens: 500,
      cache_creation_input_tokens: 0,
      model: "claude-sonnet-4-20250514",
    },
  },
  received_at: "2026-03-13T22:00:00Z",
  provider: "claude_code",
});

/** A SessionStart event (no token data expected). */
const makeWrappedSessionStart = (sessionId: string) => ({
  session_id: sessionId,
  event_type: "session_start",
  payload: {
    session_id: sessionId,
  },
  received_at: "2026-03-13T21:59:00Z",
  provider: "claude_code",
});

/** An OTel tool_result event -- drives toolCallCount under the
 *  OTel-authoritative policy. */
const makeWrappedToolResult = (sessionId: string) => ({
  session_id: sessionId,
  event_type: "tool_result",
  payload: {
    session_id: sessionId,
    tool_name: "Read",
    success: true,
    duration_ms: 120,
  },
  received_at: "2026-03-13T22:00:00Z",
  provider: "otel",
});

/** A hook prompt_submit with usage -- refreshes context window but
 *  must NOT credit tokens/cost under the OTel-authoritative policy. */
const makeWrappedHookPromptSubmit = (sessionId: string) => ({
  session_id: sessionId,
  event_type: "prompt_submit",
  payload: {
    session_id: sessionId,
    usage: {
      input_tokens: 3000,
      output_tokens: 1500,
      cache_read_input_tokens: 0,
      cache_creation_input_tokens: 0,
      model: "claude-opus-4-20250514",
    },
  },
  received_at: "2026-03-13T22:01:00Z",
  provider: "claude_code",
});

// ---------------------------------------------------------------------------
// Integration tests
// ---------------------------------------------------------------------------

describe("Event pipeline integration: DB event → hookBridge → metricsStore", () => {
  beforeAll(() => {
    // Initialize plugin system once (same as App.tsx does on mount)
    resetHookBridge();
    loadPlugins(
      [norbertSessionPlugin, norbertUsagePlugin],
      createPluginRegistry(),
      createNorbertAPI,
    );
  });

  it("OTel api_request with usage data produces non-zero tokens and cost in the store", () => {
    const before = usageMetricsStore.getMetrics();
    const event = makeWrappedApiRequestWithUsage("sess-integration-1");

    deliverHookEvent("session-event", event);

    const after = usageMetricsStore.getMetrics();
    const deltaTokens = after.totalTokens - before.totalTokens;
    // 1200 input + 400 output + 500 cache_read = 2100 (cache tokens
    // are billed and now counted in totalTokens so the displayed total
    // matches what sessionCost was computed against).
    expect(deltaTokens).toBe(2100);
    expect(after.inputTokens - before.inputTokens).toBe(1200);
    expect(after.outputTokens - before.outputTokens).toBe(400);
    expect(after.cacheReadTokens - before.cacheReadTokens).toBe(500);
    expect(after.sessionCost).toBeGreaterThan(before.sessionCost);
    expect(after.totalEventCount).toBeGreaterThan(before.totalEventCount);
  });

  it("hook tool_call_end refreshes context window but does not credit cost", () => {
    const before = usageMetricsStore.getMetrics();
    const event = makeWrappedHookToolCallEndWithUsage("sess-integration-ctx");

    deliverHookEvent("session-event", event);

    const after = usageMetricsStore.getMetrics();
    expect(after.totalTokens).toBe(before.totalTokens);
    expect(after.sessionCost).toBe(before.sessionCost);
    expect(after.contextWindowTokens).toBe(1700); // 1200 input + 500 cache_read
    expect(after.totalEventCount).toBe(before.totalEventCount + 1);
  });

  it("session_start event increments activeAgentCount without adding tokens", () => {
    const before = usageMetricsStore.getMetrics();
    const event = makeWrappedSessionStart("sess-integration-2");

    deliverHookEvent("session-event", event);

    const after = usageMetricsStore.getMetrics();
    expect(after.activeAgentCount).toBe(before.activeAgentCount + 1);
    expect(after.totalTokens).toBe(before.totalTokens); // no change
    expect(after.sessionCost).toBe(before.sessionCost); // no change
    expect(after.totalEventCount).toBe(before.totalEventCount + 1);
  });

  it("OTel tool_result increments toolCallCount without adding tokens", () => {
    const before = usageMetricsStore.getMetrics();
    const event = makeWrappedToolResult("sess-integration-3");

    deliverHookEvent("session-event", event);

    const after = usageMetricsStore.getMetrics();
    expect(after.toolCallCount).toBe(before.toolCallCount + 1);
    expect(after.totalTokens).toBe(before.totalTokens); // no change
  });

  it("hook prompt_submit with usage refreshes context without adding tokens/cost", () => {
    const before = usageMetricsStore.getMetrics();
    const event = makeWrappedHookPromptSubmit("sess-integration-4");

    deliverHookEvent("session-event", event);

    const after = usageMetricsStore.getMetrics();
    expect(after.totalTokens).toBe(before.totalTokens);
    expect(after.sessionCost).toBe(before.sessionCost);
    // 3000 input + 0 cache tokens for Opus (200k window) => 1.5%
    expect(after.contextWindowTokens).toBe(3000);
  });

  it("time series buffer receives samples when api_request events flow", () => {
    const timeSeries = usageMetricsStore.getTimeSeries();
    // Previous api_request events should have pushed samples
    expect(timeSeries.samples.length).toBeGreaterThanOrEqual(1);
    expect(timeSeries.samples[0].tokenRate).toBeGreaterThan(0);
  });
});
